import React, { useState } from 'react';
import {
  Box,
  Typography,
  TextField,
  Button,
  Paper,
  CircularProgress,
  Alert,
  Chip
} from '@mui/material';
import {
  Send,
  Security,
  CheckCircle,
  Info
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { analyzeMessage } from '../services/api';

const MessageAnalyzer = () => {
  const [message, setMessage] = useState('');
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [analysisHistory, setAnalysisHistory] = useState([]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!message.trim()) {
      return;
    }

    setLoading(true);
    
    try {
      const response = await analyzeMessage({ text: message });
      setResult(response.data);
      
      // Add to history
      const newAnalysis = {
        text: message,
        result: response.data,
        timestamp: new Date().toISOString()
      };
      
      setAnalysisHistory(prev => [newAnalysis, ...prev].slice(0, 5));
      
      setMessage('');
    } catch (error) {
      console.error('Analysis error:', error);
      setResult({
        is_bullying: false,
        message: 'Error analyzing message. Please try again.',
        confidence: 0
      });
    } finally {
      setLoading(false);
    }
  };

  const getConfidenceColor = (confidence) => {
    if (confidence > 0.7) return '#f44336';
    if (confidence > 0.4) return '#ff9800';
    return '#4caf50';
  };

  return (
    <Box>
      <Typography variant="h4" sx={{ mb: 4, fontWeight: 'bold', color: '#333' }}>
        Message Analyzer
      </Typography>

      <Paper sx={{ p: 4, mb: 4, boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <Typography variant="body1" sx={{ mb: 3, color: '#666' }}>
          Enter a message to analyze for potential cyberbullying content.
        </Typography>

        <form onSubmit={handleSubmit}>
          <TextField
            fullWidth
            multiline
            rows={4}
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Enter a message to analyze..."
            disabled={loading}
            sx={{ mb: 3 }}
          />
          
          <Button
            type="submit"
            variant="contained"
            size="large"
            disabled={loading || !message.trim()}
            startIcon={loading ? <CircularProgress size={20} /> : <Send />}
            sx={{ py: 1.5, px: 4 }}
          >
            {loading ? 'Analyzing...' : 'Analyze Message'}
          </Button>
        </form>
      </Paper>

      {result && (
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          <Paper
            sx={{
              p: 3,
              mb: 4,
              borderLeft: `4px solid ${result.is_bullying ? '#f44336' : '#4caf50'}`,
              boxShadow: '0 4px 6px rgba(0,0,0,0.1)'
            }}
          >
            <Box display="flex" alignItems="center" mb={2}>
              {result.is_bullying ? (
                <Security sx={{ fontSize: 32, color: '#f44336', mr: 2 }} />
              ) : (
                <CheckCircle sx={{ fontSize: 32, color: '#4caf50', mr: 2 }} />
              )}
              <Typography variant="h6">
                {result.is_bullying ? 'Cyberbullying Detected' : 'Message is Safe'}
              </Typography>
            </Box>

            <Alert
              severity={result.is_bullying ? 'error' : 'success'}
              sx={{ mb: 2 }}
            >
              {result.message}
            </Alert>

            <Box>
              <Typography variant="body2" sx={{ mb: 1 }}>
                Confidence Level
              </Typography>
              <Box display="flex" alignItems="center" gap={2}>
                <Box
                  sx={{
                    flex: 1,
                    height: 8,
                    backgroundColor: '#e0e0e0',
                    borderRadius: 4,
                    overflow: 'hidden'
                  }}
                >
                  <Box
                    sx={{
                      width: `${(result.confidence || 0) * 100}%`,
                      height: '100%',
                      backgroundColor: getConfidenceColor(result.confidence || 0),
                      transition: 'width 0.3s ease'
                    }}
                  />
                </Box>
                <Typography variant="body2" sx={{ minWidth: 60, textAlign: 'right' }}>
                  {((result.confidence || 0) * 100).toFixed(1)}%
                </Typography>
              </Box>
            </Box>
          </Paper>
        </motion.div>
      )}

      {analysisHistory.length > 0 && (
        <Paper sx={{ p: 3, boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          <Typography variant="h6" sx={{ mb: 3, fontWeight: 'bold' }}>
            Recent Analysis
          </Typography>
          <Box>
            {analysisHistory.map((item, index) => (
              <Box
                key={index}
                sx={{
                  py: 2,
                  borderBottom: index < analysisHistory.length - 1 ? '1px solid #e0e0e0' : 'none'
                }}
              >
                <Typography variant="body2" sx={{ mb: 1 }}>
                  {item.text}
                </Typography>
                <Box display="flex" alignItems="center" gap={2}>
                  <Chip
                    icon={item.result.is_bullying ? <Security /> : <CheckCircle />}
                    label={item.result.is_bullying ? 'Cyberbullying' : 'Safe'}
                    color={item.result.is_bullying ? 'error' : 'success'}
                    size="small"
                  />
                  <Typography variant="caption" color="text.secondary">
                    {new Date(item.timestamp).toLocaleString()}
                  </Typography>
                </Box>
              </Box>
            ))}
          </Box>
        </Paper>
      )}

      <Paper sx={{ p: 3, mt: 3, backgroundColor: '#f5f5f5' }}>
        <Box display="flex" alignItems="center" gap={1}>
          <Info color="action" />
          <Typography variant="body2" color="text.secondary">
            This system uses machine learning to detect potential cyberbullying. Results should be reviewed by human moderators.
          </Typography>
        </Box>
      </Paper>
    </Box>
  );
};

export default MessageAnalyzer;